module max_finder (
    input [4:0] A,
    input [4:0] B,
    input [4:0] C,
    output reg [4:0] min_out
);
    always @(*) begin
        if (A >= B && A >= C)
            min_out = A;
        else if (B >= A && B >= C)
            min_out = B;
        else
            min_out = C;
    end
endmodule
